// React-based SPA with OAuth 2.0 Authorization Code Flow

import React, { useState, useEffect } from 'react';
import queryString from 'query-string';

const AUTHORIZATION_URL = 'https://authorization-server.com/auth';
const TOKEN_URL = 'https://authorization-server.com/token';
const CLIENT_ID = 'your-client-id';
const REDIRECT_URI = 'http://localhost:3000';
const SCOPE = 'your-scope';
const RESPONSE_TYPE = 'code';

function App() {
  const [authCode, setAuthCode] = useState(null);
  const [accessToken, setAccessToken] = useState(localStorage.getItem('access_token'));

  useEffect(() => {
    const parsed = queryString.parse(window.location.search);
    if (parsed.code) {
      setAuthCode(parsed.code);
    }
  }, []);

  useEffect(() => {
    if (authCode && !accessToken) {
      exchangeCodeForToken(authCode);
    }
  }, [authCode, accessToken]);

  const exchangeCodeForToken = async (code) => {
    try {
      const response = await fetch(TOKEN_URL, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: new URLSearchParams({
          grant_type: 'authorization_code',
          code: code,
          redirect_uri: REDIRECT_URI,
          client_id: CLIENT_ID,
        }),
      });
      const data = await response.json();
      if (data.access_token) {
        setAccessToken(data.access_token);
        localStorage.setItem('access_token', data.access_token);
      }
    } catch (error) {
      console.error('Failed to exchange code for token', error);
    }
  };

  const initiateOAuthFlow = () => {
    const authUrl = `${AUTHORIZATION_URL}?client_id=${CLIENT_ID}&redirect_uri=${REDIRECT_URI}&response_type=${RESPONSE_TYPE}&scope=${SCOPE}`;
    window.location.href = authUrl;
  };

  return (
    <div className="App">
      {accessToken ? (
        <div>
          <h1>Authenticated</h1>
          <p>Your access token is stored in localStorage.</p>
        </div>
      ) : (
        <button onClick={initiateOAuthFlow}>Login with OAuth</button>
      )}
    </div>
  );
}

export default App;